import json
import pickle
from io import BytesIO

def lambda_handler(event, context):
    try:
        # Extract the JSON payload from the event
        payload = event['body']
        
        # Deserialize the JSON payload using pickle
        user_actions = pickle.loads(payload)
        
        # Process the user actions (example: print them)
        for action in user_actions:
            print(action)
        
        return {
            'statusCode': 200,
            'body': json.dumps('User actions processed successfully')
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error processing user actions: {str(e)}')
        }